// ============================================================
// PALISADE ONE — SOCIAL MEDIA CONTENT QUEUE
// ============================================================
// Edit this array to add/change scheduled posts.
// The workflow picks the next unposted item each time it runs.
// After posting, it marks the item as posted via static data.
//
// Fields:
//   id        — unique identifier
//   date      — target date (YYYY-MM-DD), for reference
//   platforms — array: 'x', 'linkedin', 'facebook', 'instagram'
//   content   — the post text
//   hashtags  — appended to content on platforms that use them
// ============================================================

const contentQueue = [
  {
    id: 'launch-1',
    date: '2026-03-06',
    platforms: ['x', 'linkedin', 'facebook'],
    content: `We just launched Palisade One.\n\nEnterprise-grade cybersecurity for small and mid-sized businesses. AI-powered EDR, 24/7 SOC monitoring, real-time SIEM — all fully managed.\n\nStarting at $399/month. No contracts. Live in days.\n\nFree cyber risk assessment: palisadeone.com/cyber-assessment.html`,
    hashtags: '#cybersecurity #MSSP #SMBsecurity #PalisadeOne'
  },
  {
    id: 'fear-1',
    date: '2026-03-07',
    platforms: ['x', 'linkedin', 'facebook'],
    content: `43% of cyberattacks target small businesses.\nOnly 14% are prepared to defend themselves.\nAverage breach cost: $4.88 million.\n\nIf you don't have EDR on every endpoint and 24/7 monitoring, you're running on hope.\n\nFind out where you stand (free): palisadeone.com/cyber-assessment.html`,
    hashtags: '#cybersecurity #databreach #ransomware #SMBsecurity'
  },
  {
    id: 'how-it-works-1',
    date: '2026-03-08',
    platforms: ['x', 'linkedin', 'facebook'],
    content: `How Palisade One works:\n\n1. Lightweight agent on every device\n2. AI analyzes every process in real time\n3. Threat detected in under 1 second\n4. Auto-contained — endpoint isolated, files quarantined\n5. SOC validates and responds\n6. You get a plain-English report\n\nNo hardware. No team to hire. Just protection.\n\npalisadeone.com/platform.html`,
    hashtags: '#cybersecurity #EDR #SIEM #managedservices #PalisadeOne'
  },
  {
    id: 'compliance-1',
    date: '2026-03-09',
    platforms: ['x', 'linkedin', 'facebook'],
    content: `If your business handles patient data, credit cards, or government contracts — you have compliance obligations.\n\nHIPAA. PCI-DSS. NIST. CMMC. SOC 2.\n\nNon-compliance = fines + lost contracts + lawsuits.\n\nCheck your compliance score in 10 minutes (free): palisadeone.com/cyber-assessment.html`,
    hashtags: '#compliance #HIPAA #PCI #NIST #CMMC #cybersecurity'
  },
  {
    id: 'value-1',
    date: '2026-03-10',
    platforms: ['x', 'linkedin', 'facebook'],
    content: `Building your own security operations center:\n- SIEM: $2,000-10,000/mo\n- EDR licenses: $5-15/endpoint/mo\n- SOC analyst: $85K-120K/yr\n- Compliance consultant: $200-400/hr\n\nTotal: $150K+ per year.\n\nPalisade One: $399/month.\n\nSame protection. Better math.\n\npalisadeone.com/contact.html`,
    hashtags: '#cybersecurity #MSSP #PalisadeOne #SMBsecurity'
  },
  {
    id: 'weekend-1',
    date: '2026-03-11',
    platforms: ['x'],
    content: `Weekend reminder: hackers don't take weekends off.\n\nOur SOC runs 24/7/365. AI never sleeps.\n\nIf your current security strategy is Windows Defender and good vibes... we should talk.\n\npalisadeone.com`,
    hashtags: '#cybersecurity #weekendsecurity #PalisadeOne'
  },
  {
    id: 'ransomware-story-1',
    date: '2026-03-12',
    platforms: ['x', 'linkedin', 'facebook'],
    content: `It's Sunday night. You get a call — your company got ransomwared.\n\nAll files encrypted. Client data exposed. Backups encrypted too.\nRansom demand: $250,000.\nBusiness halted for weeks.\n\nThis happens to 1,400+ businesses per day.\n\nOr... you have Palisade One. The attack was detected in 0.8 seconds. Endpoint isolated. Files quarantined. You never even knew it happened.\n\nThat's the difference.\n\npalisadeone.com/cyber-assessment.html`,
    hashtags: '#cybersecurity #ransomware #SMBsecurity #PalisadeOne'
  }
];

// Get posted IDs from static data
const staticData = $getWorkflowStaticData('global');
const postedIds = staticData.postedIds || [];

// Find next unposted item
const nextPost = contentQueue.find(item => !postedIds.includes(item.id));

if (!nextPost) {
  // All posts have been sent — reset queue
  staticData.postedIds = [];
  return [{ json: { error: 'All posts sent. Queue reset. Add new content or it will cycle.' } }];
}

// Mark as posted
postedIds.push(nextPost.id);
staticData.postedIds = postedIds;

// Build output for each platform
const fullContent = nextPost.content + '\n\n' + nextPost.hashtags;

return [{
  json: {
    id: nextPost.id,
    content: fullContent,
    contentNoHashtags: nextPost.content,
    hashtags: nextPost.hashtags,
    platforms: nextPost.platforms,
    postToX: nextPost.platforms.includes('x'),
    postToLinkedIn: nextPost.platforms.includes('linkedin'),
    postToFacebook: nextPost.platforms.includes('facebook'),
    postToInstagram: nextPost.platforms.includes('instagram')
  }
}];
